namespace sv_c2f328e51eae481fa4b2b1c582209318.Models;

public class WizardData
{
    public PersonalInfoData PersonalInfo { get; set; } = new();
    public ExperienceData Experience { get; set; } = new();
    public ReferencesData References { get; set; } = new();

    public bool IsPersonalInfoComplete =>
        !string.IsNullOrWhiteSpace(PersonalInfo.FullName)
        && !string.IsNullOrWhiteSpace(PersonalInfo.Email);

    public bool IsExperienceComplete => Experience.Jobs.Count > 0;

    public bool IsReferencesComplete => References.Contacts.Count > 0;
}

public class PersonalInfoData
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceData
{
    public List<JobEntry> Jobs { get; set; } = new();
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferencesData
{
    public List<ReferenceContact> Contacts { get; set; } = new();
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_c2f328e51eae481fa4b2b1c582209318.Models;

namespace sv_c2f328e51eae481fa4b2b1c582209318.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by a session cookie.
/// Both static SSR (layout) and interactive Server (pages) components
/// resolve the same instance, so they share state through the session ID.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId) =>
        _store.GetOrAdd(sessionId, _ => new WizardData());

    public bool TryGet(string sessionId, out WizardData? data) =>
        _store.TryGetValue(sessionId, out data);

    /// <summary>
    /// Reads (or creates) the session-id cookie and returns it.
    /// Safe to call from any SSR or prerender context that has HttpContext.
    /// </summary>
    public static string ResolveSessionId(HttpContext httpContext)
    {
        const string cookieName = "WizardSessionId";

        if (httpContext.Request.Cookies.TryGetValue(cookieName, out var existing)
            && !string.IsNullOrEmpty(existing))
        {
            return existing;
        }

        var id = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(cookieName, id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
        return id;
    }
}

@inherits LayoutComponentBase
@using sv_c2f328e51eae481fa4b2b1c582209318.Services
@using sv_c2f328e51eae481fa4b2b1c582209318.Models
@inject WizardStateStore StateStore
@inject NavigationManager Nav

@* This layout renders statically (SSR). It reads the URL to determine
   the current step and checks the singleton state store for completion. *@

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <span class="wizard-title">Job Application — Step @currentStep of @totalSteps</span>
        </div>

        <nav class="wizard-progress px-4 py-3">
            @for (int i = 0; i < steps.Length; i++)
            {
                var step = steps[i];
                var stepNumber = i + 1;
                var isCurrent = stepNumber == currentStep;
                var isCompleted = IsStepCompleted(stepNumber);

                <a href="@step.Href"
                   class="wizard-step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "")">
                    <span class="step-number">
                        @if (isCompleted && !isCurrent)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            @stepNumber
                        }
                    </span>
                    <span class="step-label">@step.Label</span>
                </a>

                @if (stepNumber < totalSteps)
                {
                    <span class="step-connector @(isCompleted ? "completed" : "")"></span>
                }
            }
        </nav>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private record StepInfo(string Href, string Label);

    private static readonly StepInfo[] steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private const int totalSteps = 4;
    private int currentStep = 1;
    private WizardData? wizardData;

    protected override void OnInitialized()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        currentStep = path switch
        {
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1,
        };

        if (HttpContext is not null)
        {
            var sessionId = WizardStateStore.ResolveSessionId(HttpContext);
            wizardData = StateStore.GetOrCreate(sessionId);
        }
    }

    private bool IsStepCompleted(int step) => step switch
    {
        1 => wizardData?.IsPersonalInfoComplete == true,
        2 => wizardData?.IsExperienceComplete == true,
        3 => wizardData?.IsReferencesComplete == true,
        _ => false,
    };
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: 3.5rem;
    display: flex;
    align-items: center;
}

.wizard-title {
    font-weight: 600;
    font-size: 1.1rem;
}

.wizard-progress {
    display: flex;
    align-items: center;
    gap: 0;
    background-color: #fff;
    border-bottom: 1px solid #e0e0e0;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    text-decoration: none;
    color: #888;
    font-size: 0.9rem;
    padding: 0.3rem 0.6rem;
    border-radius: 0.4rem;
    transition: background-color 0.15s;
}

.wizard-step:hover {
    background-color: #f0f0f0;
    text-decoration: none;
}

.wizard-step.current {
    color: #0d6efd;
