using System.Collections.Concurrent;
using sv_c2f328e51eae481fa4b2b1c582209318.Models;

namespace sv_c2f328e51eae481fa4b2b1c582209318.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by a session cookie.
/// Both static SSR (layout) and interactive Server (pages) components
/// resolve the same instance, so they share state through the session ID.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId) =>
        _store.GetOrAdd(sessionId, _ => new WizardData());

    public bool TryGet(string sessionId, out WizardData? data) =>
        _store.TryGetValue(sessionId, out data);

    /// <summary>
    /// Reads (or creates) the session-id cookie and returns it.
    /// Safe to call from any SSR or prerender context that has HttpContext.
    /// </summary>
    public static string ResolveSessionId(HttpContext httpContext)
    {
        const string cookieName = "WizardSessionId";

        if (httpContext.Request.Cookies.TryGetValue(cookieName, out var existing)
            && !string.IsNullOrEmpty(existing))
        {
            return existing;
        }

        var id = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(cookieName, id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(4)
        });
        return id;
    }
}

