@inherits LayoutComponentBase
@using sv_c2f328e51eae481fa4b2b1c582209318.Services
@using sv_c2f328e51eae481fa4b2b1c582209318.Models
@inject WizardStateStore StateStore
@inject NavigationManager Nav

@* This layout renders statically (SSR). It reads the URL to determine
   the current step and checks the singleton state store for completion. *@

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <span class="wizard-title">Job Application — Step @currentStep of @totalSteps</span>
        </div>

        <nav class="wizard-progress px-4 py-3">
            @for (int i = 0; i < steps.Length; i++)
            {
                var step = steps[i];
                var stepNumber = i + 1;
                var isCurrent = stepNumber == currentStep;
                var isCompleted = IsStepCompleted(stepNumber);

                <a href="@step.Href"
                   class="wizard-step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "")">
                    <span class="step-number">
                        @if (isCompleted && !isCurrent)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            @stepNumber
                        }
                    </span>
                    <span class="step-label">@step.Label</span>
                </a>

                @if (stepNumber < totalSteps)
                {
                    <span class="step-connector @(isCompleted ? "completed" : "")"></span>
                }
            }
        </nav>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private record StepInfo(string Href, string Label);

    private static readonly StepInfo[] steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private const int totalSteps = 4;
    private int currentStep = 1;
    private WizardData? wizardData;

    protected override void OnInitialized()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        currentStep = path switch
        {
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1,
        };

        if (HttpContext is not null)
        {
            var sessionId = WizardStateStore.ResolveSessionId(HttpContext);
            wizardData = StateStore.GetOrCreate(sessionId);
        }
    }

    private bool IsStepCompleted(int step) => step switch
    {
        1 => wizardData?.IsPersonalInfoComplete == true,
        2 => wizardData?.IsExperienceComplete == true,
        3 => wizardData?.IsReferencesComplete == true,
        _ => false,
    };
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: 3.5rem;
    display: flex;
    align-items: center;
}

.wizard-title {
    font-weight: 600;
    font-size: 1.1rem;
}

.wizard-progress {
    display: flex;
    align-items: center;
    gap: 0;
    background-color: #fff;
    border-bottom: 1px solid #e0e0e0;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    text-decoration: none;
    color: #888;
    font-size: 0.9rem;
    padding: 0.3rem 0.6rem;
    border-radius: 0.4rem;
    transition: background-color 0.15s;
}

.wizard-step:hover {
    background-color: #f0f0f0;
    text-decoration: none;
}

.wizard-step.current {
    color: #0d6efd;
    font-weight: 600;
}

.wizard-step.completed {
    color: #198754;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.6rem;
    height: 1.6rem;
    border-radius: 50%;
    border: 2px solid #ccc;
    font-size: 0.8rem;
    font-weight: 700;
    flex-shrink: 0;
}

.wizard-step.current .step-number {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.wizard-step.completed .step-number {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background-color: #ccc;
    flex-shrink: 0;
}

.step-connector.completed {
    background-color: #198754;
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .top-row {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .top-row, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

