arguments.file_text:
@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_c2f328e51eae481fa4b2b1c582209318.Models
@using sv_c2f328e51eae481fa4b2b1c582209318.Services
@inject WizardStateStore StateStore
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Personal Info</PageTitle>

<h1>Personal Information</h1>

@if (data is not null)
{
    <div class="mb-3" style="max-width: 500px;">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="data.FullName" @bind:event="oninput" />
    </div>

    <div class="mb-3" style="max-width: 500px;">
        <label class="form-label">Email Address</label>
        <input type="email" class="form-control" @bind="data.Email" @bind:event="oninput" />
    </div>

    <button class="btn btn-primary" @onclick="Next" disabled="@(!IsValid)">
        Next: Experience →
    </button>
}

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private string? sessionId;
    private PersonalInfoData? data;
    private PersistentComponentStateSubscription sub;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(data?.FullName)
        && !string.IsNullOrWhiteSpace(data?.Email);

    protected override void OnInitialized()
    {
        sub = PersistentState.RegisterOnPersisting(PersistSession);

        if (HttpContext is not null)
        {
            sessionId = WizardStateStore.ResolveSessionId(HttpContext);
        }
        else if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            sessionId = restored;
        }

        if (sessionId is not null)
        {
            data = StateStore.GetOrCreate(sessionId).PersonalInfo;
        }
    }

    private Task PersistSession()
    {
        PersistentState.PersistAsJson("wizardSessionId", sessionId);
        return Task.CompletedTask;
    }

    private void Next() => Nav.NavigateTo("/apply/experience");

    public void Dispose() => sub.Dispose();
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_c2f328e51eae481fa4b2b1c582209318.Models
@using sv_c2f328e51eae481fa4b2b1c582209318.Services
@inject WizardStateStore StateStore
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Experience</PageTitle>

<h1>Work Experience</h1>

@if (wizardData is not null)
{
    @foreach (var (job, index) in wizardData.Experience.Jobs.Select((j, i) => (j, i)))
    {
        <div class="card mb-3" style="max-width: 600px;">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-start">
                    <h6 class="card-subtitle text-muted">Job @(index + 1)</h6>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
                </div>
                <div class="mb-2 mt-2">
                    <label class="form-label">Company</label>
                    <input class="form-control" @bind="job.Company" @bind:event="oninput" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Job Title</label>
                    <input class="form-control" @bind="job.Title" @bind:event="oninput" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Duration</label>
                    <input class="form-control" @bind="job.Duration" @bind:event="oninput"
                           placeholder="e.g. Jan 2020 – Mar 2023" />
                </div>
            </div>
        </div>
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

    <div>
        <button class="btn btn-outline-secondary me-2" @onclick="Back">← Back</button>
        <button class="btn btn-primary" @onclick="Next"
                disabled="@(wizardData.Experience.Jobs.Count == 0)">
            Next: References →
        </button>
    </div>
}

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    private string? sessionId;
    private WizardData? wizardData;
    private PersistentComponentStateSubscription sub;

    protected override void OnInitialized()
    {
        sub = PersistentState.RegisterOnPersisting(PersistSession);

        if (HttpContext is not null)
            sessionId = WizardStateStore.ResolveSessionId(HttpContext);
        else if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
            sessionId = restored;

        if (sessionId is not null)
            wizardData = StateStore.GetOrCreate(sessionId);
    }

    private Task PersistSession()
